const MANIFEST_JSON = atob("");
const MANIFEST: Record<string, string> = JSON.parse(MANIFEST_JSON);

const MIME: Record<string, string> = {
  ".html":"text/html; charset=utf-8",
  ".js":"application/javascript; charset=utf-8",
  ".mjs":"application/javascript; charset=utf-8",
  ".css":"text/css; charset=utf-8",
  ".json":"application/json; charset=utf-8",
  ".png":"image/png",
  ".jpg":"image/jpeg",
  ".jpeg":"image/jpeg",
  ".gif":"image/gif",
  ".svg":"image/svg+xml",
  ".ico":"image/x-icon",
  ".woff":"font/woff",
  ".woff2":"font/woff2",
  ".ttf":"font/ttf",
  ".webm":"video/webm",
  ".mp4":"video/mp4",
  ".webp":"image/webp",
  ".mp3":"audio/mpeg",
  ".wav":"audio/wav",
  ".ogg":"audio/ogg",
  ".m4a":"audio/mp4",
  ".flac":"audio/flac",
  ".aac":"audio/aac",
};

function getMime(path: string): string {
  const idx = path.lastIndexOf(".");
  if (idx < 0) return "application/octet-stream";
  const ext = path.slice(idx);
  return MIME[ext] ?? "application/octet-stream";
}

function resolveFile(path: string): Uint8Array | null {
  const raw = MANIFEST[path];
  if (!raw) return null;
  if (raw.startsWith("BIN:")) {
    const b64 = raw.slice(4);
    const bin = atob(b64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    return bytes;
  }
  return new TextEncoder().encode(raw);
}

const port = parseInt(Deno.env.get("PORT") ?? "8000");
Deno.serve({ port }, (req: Request): Response => {
  const url = new URL(req.url);
  let pathname = url.pathname;

  // Remove trailing slash
  if (pathname.endsWith("/") && pathname.length > 1) {
    pathname = pathname.slice(0, -1);
  }

  // Try exact match
  const file = resolveFile(pathname);
  if (file) {
    return new Response(file, {
      headers: {
        "content-type": getMime(pathname),
        "cache-control": pathname.includes("/assets/")
          ? "public, max-age=31536000, immutable"
          : "no-cache",
      },
    });
  }

  // SPA fallback — serve index.html for non-file routes
  const index = resolveFile("/index.html");
  if (index) {
    return new Response(index, {
      headers: { "content-type": "text/html; charset=utf-8" },
    });
  }

  return new Response("Not Found", { status: 404 });
});
